  const minutosInput = convertirAHorasMinutos(horaInput);

  // Definir rangos en minutos
  const inicioAtencion = convertirAHorasMinutos("08:00");
  const finAtencion = convertirAHorasMinutos("18:00");
  const inicioAlmuerzo = convertirAHorasMinutos("12:00");
  const finAlmuerzo = convertirAHorasMinutos("14:00");

  let estado = "válido";
  let justificacion = "";

  if (minutosInput < inicioAtencion || minutosInput >= finAtencion) {
    estado = "inválido";
    justificacion = "Hora fuera de horario de atención";
  } else if (minutosInput >= inicioAlmuerzo && minutosInput < finAlmuerzo) {
    estado = "inválido";
    justificacion = "Horario de almuerzo";
  }

  item.json.horaEstado = estado;
  item.json.horaJustificacion = justificacion;
}

return $input.all();

